import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import { createAnalyticsRoutes } from '../../src/routes/analytics.routes.js';
import type { RouteRequest } from '../../src/routes/types.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';

function makeOrder(overrides: Partial<Order> = {}): Order {
  return {
    id: 'order-001',
    userId: 'user-001',
    items: [
      { productId: 'prod-1', name: 'Widget', quantity: 2, unitPrice: 10 },
    ],
    total: 20,
    status: 'confirmed',
    createdAt: new Date('2025-01-15'),
    updatedAt: new Date('2025-01-15'),
    ...overrides,
  };
}

function makeUser(overrides: Partial<User> = {}): User {
  return {
    id: 'user-001',
    email: 'test@example.com',
    name: 'Test User',
    role: 'customer',
    createdAt: new Date('2025-01-01'),
    updatedAt: new Date('2025-01-01'),
    ...overrides,
  };
}

function makeRequest(query: Record<string, string> = {}): RouteRequest {
  return { params: {}, query };
}

describe('Analytics Routes', () => {
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let analyticsService: AnalyticsService;
  let routes: ReturnType<typeof createAnalyticsRoutes>;

  beforeEach(() => {
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    analyticsService = new AnalyticsService(orderRepo, userRepo);
    routes = createAnalyticsRoutes(analyticsService);

    // Seed data
    userRepo.save(makeUser());
    userRepo.save(makeUser({ id: 'user-002', email: 'b@example.com', name: 'User 2', role: 'admin', createdAt: new Date('2025-02-01') }));
    orderRepo.save(makeOrder());
    orderRepo.save(makeOrder({
      id: 'order-002',
      userId: 'user-002',
      items: [{ productId: 'prod-2', name: 'Gadget', quantity: 1, unitPrice: 50 }],
      total: 50,
      status: 'delivered',
      createdAt: new Date('2025-01-20'),
      updatedAt: new Date('2025-01-20'),
    }));
    orderRepo.save(makeOrder({
      id: 'order-003',
      status: 'cancelled',
      total: 20,
      createdAt: new Date('2025-02-10'),
      updatedAt: new Date('2025-02-10'),
    }));
  });

  // --- getOrderMetrics ---
  describe('getOrderMetrics', () => {
    it('returns order metrics without date filters', () => {
      const res = routes.getOrderMetrics(makeRequest());
      expect(res.status).toBe(200);
      expect(res.data).toBeDefined();
      expect(res.data!.totalOrders).toBe(3);
      expect(res.data!.totalRevenue).toBe(90);
      expect(res.data!.averageOrderValue).toBe(30);
    });

    it('filters by date range', () => {
      const res = routes.getOrderMetrics(makeRequest({
        startDate: '2025-01-01',
        endDate: '2025-01-31',
      }));
      expect(res.status).toBe(200);
      expect(res.data!.totalOrders).toBe(2);
    });

    it('returns 400 for invalid startDate', () => {
      const res = routes.getOrderMetrics(makeRequest({ startDate: 'not-a-date' }));
      expect(res.status).toBe(400);
      expect(res.error).toContain('Invalid date');
    });

    it('returns 400 when startDate is after endDate', () => {
      const res = routes.getOrderMetrics(makeRequest({
        startDate: '2025-03-01',
        endDate: '2025-01-01',
      }));
      expect(res.status).toBe(400);
      expect(res.error).toContain('startDate');
    });
  });

  // --- getUserMetrics ---
  describe('getUserMetrics', () => {
    it('returns user metrics without date filters', () => {
      const res = routes.getUserMetrics(makeRequest());
      expect(res.status).toBe(200);
      expect(res.data!.totalUsers).toBe(2);
      expect(res.data!.usersByRole).toEqual({ customer: 1, admin: 1 });
    });

    it('counts new users in period', () => {
      const res = routes.getUserMetrics(makeRequest({
        startDate: '2025-01-15',
        endDate: '2025-03-01',
      }));
      expect(res.status).toBe(200);
      expect(res.data!.newUsersInPeriod).toBe(1);
    });

    it('returns 400 for invalid endDate', () => {
      const res = routes.getUserMetrics(makeRequest({ endDate: 'bad' }));
      expect(res.status).toBe(400);
      expect(res.error).toContain('Invalid date');
    });

    it('returns 400 when startDate is after endDate', () => {
      const res = routes.getUserMetrics(makeRequest({
        startDate: '2025-06-01',
        endDate: '2025-01-01',
      }));
      expect(res.status).toBe(400);
      expect(res.error).toContain('startDate');
    });
  });

  // --- getTopProducts ---
  describe('getTopProducts', () => {
    it('returns top products sorted by revenue', () => {
      const res = routes.getTopProducts(makeRequest());
      expect(res.status).toBe(200);
      expect(res.data!.length).toBe(2);
      // Gadget ($50) > Widget ($20) — cancelled order excluded
      expect(res.data![0].name).toBe('Gadget');
      expect(res.data![1].name).toBe('Widget');
    });

    it('respects limit parameter', () => {
      const res = routes.getTopProducts(makeRequest({ limit: '1' }));
      expect(res.status).toBe(200);
      expect(res.data!.length).toBe(1);
    });

    it('returns 400 for non-integer limit', () => {
      const res = routes.getTopProducts(makeRequest({ limit: '2.5' }));
      expect(res.status).toBe(400);
      expect(res.error).toContain('positive integer');
    });

    it('returns 400 for zero limit', () => {
      const res = routes.getTopProducts(makeRequest({ limit: '0' }));
      expect(res.status).toBe(400);
      expect(res.error).toContain('positive integer');
    });

    it('returns 400 for negative limit', () => {
      const res = routes.getTopProducts(makeRequest({ limit: '-1' }));
      expect(res.status).toBe(400);
      expect(res.error).toContain('positive integer');
    });

    it('filters by date range', () => {
      const res = routes.getTopProducts(makeRequest({
        startDate: '2025-01-01',
        endDate: '2025-01-31',
      }));
      expect(res.status).toBe(200);
      // Only Jan orders (both non-cancelled)
      expect(res.data!.length).toBe(2);
    });
  });

  // --- getTimeSeries ---
  describe('getTimeSeries', () => {
    it('returns revenue time series', () => {
      const res = routes.getTimeSeries(makeRequest({
        metric: 'revenue',
        startDate: '2025-01-15',
        endDate: '2025-01-20',
        granularity: 'day',
      }));
      expect(res.status).toBe(200);
      expect(res.data!.metric).toBe('revenue');
      expect(res.data!.dataPoints.length).toBe(6); // 6 days inclusive
    });

    it('returns orderCount time series', () => {
      const res = routes.getTimeSeries(makeRequest({
        metric: 'orderCount',
        startDate: '2025-01-01',
        endDate: '2025-01-31',
      }));
      expect(res.status).toBe(200);
      expect(res.data!.metric).toBe('orderCount');
    });

    it('defaults granularity to day', () => {
      const res = routes.getTimeSeries(makeRequest({
        metric: 'revenue',
        startDate: '2025-01-15',
        endDate: '2025-01-20',
      }));
      expect(res.status).toBe(200);
      expect(res.data!.dataPoints.length).toBe(6);
    });

    it('returns 400 when metric is missing', () => {
      const res = routes.getTimeSeries(makeRequest({
        startDate: '2025-01-01',
        endDate: '2025-01-31',
      }));
      expect(res.status).toBe(400);
      expect(res.error).toContain('metric');
    });

    it('returns 400 for invalid metric', () => {
      const res = routes.getTimeSeries(makeRequest({
        metric: 'invalid',
        startDate: '2025-01-01',
        endDate: '2025-01-31',
      }));
      expect(res.status).toBe(400);
      expect(res.error).toContain('Invalid metric');
    });

    it('returns 400 when startDate is missing', () => {
      const res = routes.getTimeSeries(makeRequest({ metric: 'revenue', endDate: '2025-01-31' }));
      expect(res.status).toBe(400);
      expect(res.error).toContain('startDate');
    });

    it('returns 400 when endDate is missing', () => {
      const res = routes.getTimeSeries(makeRequest({ metric: 'revenue', startDate: '2025-01-01' }));
      expect(res.status).toBe(400);
      expect(res.error).toContain('endDate');
    });

    it('returns 400 for invalid granularity', () => {
      const res = routes.getTimeSeries(makeRequest({
        metric: 'revenue',
        startDate: '2025-01-01',
        endDate: '2025-01-31',
        granularity: 'year',
      }));
      expect(res.status).toBe(400);
      expect(res.error).toContain('Invalid granularity');
    });

    it('returns 400 when startDate is after endDate', () => {
      const res = routes.getTimeSeries(makeRequest({
        metric: 'revenue',
        startDate: '2025-03-01',
        endDate: '2025-01-01',
      }));
      expect(res.status).toBe(400);
      expect(res.error).toContain('startDate');
    });
  });

  // --- getDashboard ---
  describe('getDashboard', () => {
    it('returns composed dashboard data', () => {
      const res = routes.getDashboard(makeRequest({
        startDate: '2025-01-01',
        endDate: '2025-02-28',
      }));
      expect(res.status).toBe(200);
      expect(res.data).toBeDefined();
      expect(res.data!.orderMetrics).toBeDefined();
      expect(res.data!.userMetrics).toBeDefined();
      expect(res.data!.revenueTimeSeries).toBeDefined();
      expect(res.data!.ordersTimeSeries).toBeDefined();
      expect(res.data!.topProducts).toBeDefined();
      expect(res.data!.generatedAt).toBeInstanceOf(Date);
      expect(res.data!.periodStart).toBeInstanceOf(Date);
      expect(res.data!.periodEnd).toBeInstanceOf(Date);
    });

    it('returns 400 when startDate is missing', () => {
      const res = routes.getDashboard(makeRequest({ endDate: '2025-01-31' }));
      expect(res.status).toBe(400);
      expect(res.error).toContain('startDate');
    });

    it('returns 400 when endDate is missing', () => {
      const res = routes.getDashboard(makeRequest({ startDate: '2025-01-01' }));
      expect(res.status).toBe(400);
      expect(res.error).toContain('endDate');
    });

    it('returns 400 when startDate is after endDate', () => {
      const res = routes.getDashboard(makeRequest({
        startDate: '2025-06-01',
        endDate: '2025-01-01',
      }));
      expect(res.status).toBe(400);
      expect(res.error).toContain('startDate');
    });

    it('returns 400 for invalid dates', () => {
      const res = routes.getDashboard(makeRequest({
        startDate: 'nope',
        endDate: '2025-01-31',
      }));
      expect(res.status).toBe(400);
      expect(res.error).toContain('Invalid date');
    });
  });
});

