+): number {
+  if (value === undefined || value === '') {
+    return defaultValue;
+  }
+  const num = Number(value);
+  if (!Number.isInteger(num) || num < 1) {
+    throw new Error(`'${paramName}' must be a positive integer, got: ${value}`);
+  }
+  return num;
+}
+
+/**
+ * Creates all analytics route handlers bound to a given AnalyticsService instance.
+ */
+export function createAnalyticsRoutes(analyticsService: AnalyticsService) {
+  const logger = new Logger('AnalyticsRoutes');
+
+  /**
+   * GET /analytics/orders
+   *
+   * Query params:
+   *   startDate? — ISO date string (YYYY-MM-DD)
+   *   endDate?   — ISO date string (YYYY-MM-DD)
+   *
+   * Returns: OrderMetricSummary
+   */
+  const getOrderMetrics: RouteHandler<OrderMetricSummary> = (
+    request: RouteRequest,
+  ): RouteResponse<OrderMetricSummary> => {
+    logger.info('GET /analytics/orders');
+    try {
+      const startDate = parseDate(request.query.startDate, 'startDate');
+      const endDate = parseDate(request.query.endDate, 'endDate');
+
+      if (startDate && endDate && startDate > endDate) {
+        return {
+          status: 400,
+          error: "'startDate' must not be after 'endDate'",
+        };
+      }
+
+      const data = analyticsService.getOrderMetrics(startDate, endDate);
+      return { status: 200, data };
+    } catch (err) {
+      const message = err instanceof Error ? err.message : 'Internal server error';
+      logger.error(`getOrderMetrics failed: ${message}`);
+      return { status: 400, error: message };
+    }
+  };
+
+  /**
+   * GET /analytics/users
+   *
+   * Query params:
+   *   startDate? — ISO date string (YYYY-MM-DD)
+   *   endDate?   — ISO date string (YYYY-MM-DD)
+   *
+   * Returns: UserMetricSummary
+   */
+  const getUserMetrics: RouteHandler<UserMetricSummary> = (
+    request: RouteRequest,
+  ): RouteResponse<UserMetricSummary> => {
+    logger.info('GET /analytics/users');
+    try {
+      const startDate = parseDate(request.query.startDate, 'startDate');
+      const endDate = parseDate(request.query.endDate, 'endDate');
+
+      if (startDate && endDate && startDate > endDate) {
+        return {
+          status: 400,
+          error: "'startDate' must not be after 'endDate'",
+        };
+      }
+
+      const data = analyticsService.getUserMetrics(startDate, endDate);
+      return { status: 200, data };
+    } catch (err) {
+      const message = err instanceof Error ? err.message : 'Internal server error';
+      logger.error(`getUserMetrics failed: ${message}`);
+      return { status: 400, error: message };
+    }
+  };
+
+  /**
+   * GET /analytics/top-products
+   *
+   * Query params:
+   *   startDate? — ISO date string (YYYY-MM-DD)
+   *   endDate?   — ISO date string (YYYY-MM-DD)
+   *   limit?     — positive integer (default 10)
+   *
+   * Returns: TopProduct[]
+   */
+  const getTopProducts: RouteHandler<TopProduct[]> = (
+    request: RouteRequest,
+  ): RouteResponse<TopProduct[]> => {
+    logger.info('GET /analytics/top-products');
+    try {
+      const startDate = parseDate(request.query.startDate, 'startDate');
+      const endDate = parseDate(request.query.endDate, 'endDate');
+      const limit = parsePositiveInt(request.query.limit, 'limit', 10);
+
+      if (startDate && endDate && startDate > endDate) {
+        return {
+          status: 400,
+          error: "'startDate' must not be after 'endDate'",
+        };
+      }
+
+      const data = analyticsService.getTopProducts(startDate, endDate, limit);
+      return { status: 200, data };
+    } catch (err) {
+      const message = err instanceof Error ? err.message : 'Internal server error';
+      logger.error(`getTopProducts failed: ${message}`);
+      return { status: 400, error: message };
+    }
+  };
+
+  /**
+   * GET /analytics/time-series
+   *
+   * Query params:
+   *   metric      — "revenue" | "orderCount" (required)
+   *   startDate   — ISO date string (required)
+   *   endDate     — ISO date string (required)
+   *   granularity? — "day" | "week" | "month" (default "day")
+   *
+   * Returns: TimeSeriesResult
+   */
+  const getTimeSeries: RouteHandler<TimeSeriesResult> = (
+    request: RouteRequest,
+  ): RouteResponse<TimeSeriesResult> => {
+    logger.info('GET /analytics/time-series');
+    try {
+      const { metric, granularity } = request.query;
+
+      if (!metric) {
+        return { status: 400, error: "Missing required parameter: 'metric'" };
+      }
+      if (!VALID_METRICS.includes(metric as typeof VALID_METRICS[number])) {
+        return {
+          status: 400,
+          error: `Invalid metric: '${metric}'. Must be one of: ${VALID_METRICS.join(', ')}`,
+        };
+      }
+
+      const startDate = parseRequiredDate(request.query.startDate, 'startDate');
+      const endDate = parseRequiredDate(request.query.endDate, 'endDate');
+
+      if (startDate > endDate) {
+        return {
+          status: 400,
+          error: "'startDate' must not be after 'endDate'",
+        };
+      }
+
+      let parsedGranularity: TimeGranularity = 'day';
+      if (granularity !== undefined && granularity !== '') {
+        if (!VALID_GRANULARITIES.includes(granularity as TimeGranularity)) {
+          return {
+            status: 400,
+            error: `Invalid granularity: '${granularity}'. Must be one of: ${VALID_GRANULARITIES.join(', ')}`,
+          };
+        }
+        parsedGranularity = granularity as TimeGranularity;
+      }
+
+      const data = analyticsService.getTimeSeries(
+        metric as 'revenue' | 'orderCount',
+        startDate,
+        endDate,
+        parsedGranularity,
+      );
+      return { status: 200, data };
+    } catch (err) {
+      const message = err instanceof Error ? err.message : 'Internal server error';
+      logger.error(`getTimeSeries failed: ${message}`);
+      return { status: 400, error: message };
+    }
+  };
+
+  /**
+   * GET /analytics/dashboard
+   *
+   * Query params:
+   *   startDate — ISO date string (required)
+   *   endDate   — ISO date string (required)
+   *
+   * Returns: DashboardData
+   */
+  const getDashboard: RouteHandler<DashboardData> = (
+    request: RouteRequest,
+  ): RouteResponse<DashboardData> => {
+    logger.info('GET /analytics/dashboard');
+    try {
+      const startDate = parseRequiredDate(request.query.startDate, 'startDate');
+      const endDate = parseRequiredDate(request.query.endDate, 'endDate');
+
+      if (startDate > endDate) {
+        return {
+          status: 400,
+          error: "'startDate' must not be after 'endDate'",
+        };
+      }
+
+      const data = analyticsService.getDashboardData(startDate, endDate);
+      return { status: 200, data };
+    } catch (err) {
+      const message = err instanceof Error ? err.message : 'Internal server error';
+      logger.error(`getDashboard failed: ${message}`);
+      return { status: 400, error: message };
+    }
+  };
+
+  return {
+    getOrderMetrics,
+    getUserMetrics,
+    getTopProducts,
+    getTimeSeries,
+    getDashboard,
+  };
+}

